%% Constants
Kt = 0.99; %turbiity coefficient: 1 for clean air, 0.5 extremely dusty/polluted air
Gsc = 4.92; %solar constant in MJ/m2h

P = 101.3*((293-0.0065*ELEV)/293)^5.26; %mean atmo press [kPa] at z; Eq. 3   
LAT_rad = LAT/180*pi; %change degrees to radians 

%% Extraterrestrial Radiation for 24 hours (page 23)
Ra = zeros(length(DOY),1); %ET radiation (MJ/m2/d)
sol_declin = zeros(length(DOY),1); %Solar declination 
ird = zeros(length(DOY),1); %inverse relative distance factor (^2) for the earth-sun [unitless]
sun_hr_angle= zeros(length(DOY),1); %sunset hour angle  

sol_declin = 0.409*sin(2*pi/365.*DOY - 1.39); %Equation 24  
ird = 1 + 0.033*cos(2*pi/365.*DOY); %Equation 23 
sun_hr_angle = acos(-tan(LAT_rad).*tan(sol_declin)); %Equation 27 
a = sin(LAT_rad).*sin(sol_declin).*sun_hr_angle; %Eq 21, part a
b = cos(LAT_rad).*cos(sol_declin).*sin(sun_hr_angle); %Eq 21, part b
Ra = 24/pi*Gsc.*ird.*(a + b); %Equation 21

%% Clearness index (Kb) calculation
sin_phi24 = zeros(length(DOY),1); %sun angle (radians)
W = zeros(length(DOY),1);   %precipitiable water in the atmosphere (mm)
Kb = zeros(length(DOY),1);  %clearness index for direct beam radiation []
Kd = zeros(length(DOY),1);  %transmissivity index for diffuse radiation []

sin_phi24 = sin(0.85 + 0.3*LAT_rad * sin(2*pi/365.*DOY-1.39) - 0.42*LAT_rad^2);%Equation D.5 XXX
W   = 0.14.*ea*P + 2.1; %Equation D.3
Kb  = 0.98*exp(((-0.00146*P)/Kt./sin_phi24) - 0.075*(W./sin_phi24).^0.4); %Equation D.2 XXX

% Diffuse radiation index (Kd) calculation: Equation D.4 
for i = 1:length(DOY)
  if Kb(i,1)>=0.15
      Kd(i,1) = 0.35 - 0.36*Kb(i,1);
  else
      Kd(i,1) = 0.18 + 0.82*Kb(i,1);
  end
end

%% Clear-sky solar radiation, finally
Rso_MJ = (Kb + Kd).*Ra; %Equation D.1 in MJ/m2/d
Rso = 1e6.*Rso_MJ./(60*60*24);% convert to in w/m2
%plot(DOY,Rso)
end

